INSERT INTO public.pipeline_updates (title, description, priority, status, is_auto_generated, batch_date) VALUES ('Frequência Automatizada por Geolocalização', 'Sistema de registro automático de presença dos alunos usando geolocalização. O professor define um raio geográfico para a sala de aula e os alunos registram presença automaticamente ao estarem dentro do perímetro durante o horário da sessão. Inclui histórico de frequência, relatórios de presença e alertas de ausência.', 'alta', 'roadmap', false, now()::date);